// Word pools for procedurally generating movie titles.
// Titles should feel witty, specific, and slightly absurd —
// like a real festival circuit film, not a generic blockbuster.
//
// generateMovieTitle() below picks a random template and fills it
// from these pools. Import and call it wherever a fake title is needed.

const fragments = {
	// "The Last ___" / "The Only ___" style
	definiteNouns: [
		"Weather Girl",
		"Normal Tuesday",
		"Honest Man in Ohio",
		"Beautiful Parking Lot",
		"Reasonable Vampire",
		"Accountant",
		"Optimist",
		"Good Diner",
		"Suburbs",
		"Long Weekend",
		"Film Student",
		"Wedding Planner",
		"Swimming Pool",
		"Dog Show",
		"Grocery Store",
		"Night Bus",
	],

	// "Midnight at the ___" / "Summer in the ___" style
	locations: [
		"the Mall",
		"the Edge of Town",
		"the Hotel Lobby",
		"the End of the Street",
		"the Old Marina",
		"the Retirement Community",
		"the Visitor Center",
		"the Botanical Garden",
		"the Airport Bar",
		"the County Fair",
		"the Laundromat",
		"the Overpass",
		"the Parking Structure",
		"the Wilderness Retreat",
		"the Neighborhood Pool",
		"the Science Museum",
		"the Outlet Mall",
		"the Conference Center",
	],

	// "A Very Normal ___" / "One Big ___" style
	eventNouns: [
		"Heist",
		"Reunion",
		"Funeral",
		"Road Trip",
		"Intervention",
		"Mistake",
		"Summer",
		"Birthday",
		"Disaster",
		"Conspiracy",
		"Breakup",
		"Comeback",
		"Proposal",
		"Alibi",
		"Renovation",
		"Promotion",
		"Apology",
		"Audition",
	],

	// Modifying adjectives for "A Very ___ Event"
	adjectives: [
		"Normal",
		"Reasonable",
		"Unnecessary",
		"Complicated",
		"Expensive",
		"Inconvenient",
		"Accidental",
		"Ambitious",
		"Reluctant",
		"Suspicious",
		"Emotional",
		"Dramatic",
		"Unfortunate",
		"Cheerful",
		"Sincere",
	],

	// Time words for "Midnight at" / "Noon at" style
	times: [
		"Midnight",
		"Noon",
		"Dusk",
		"3 AM",
		"Late Afternoon",
		"Last Call",
		"Golden Hour",
		"Tuesday Morning",
		"Friday Night",
		"Sunday Afternoon",
	],

	// Occupations / character types for "The Last ___ in [place]"
	occupations: [
		"Librarian",
		"Dentist",
		"Vet",
		"Travel Agent",
		"Cartographer",
		"Dog Walker",
		"Wedding Singer",
		"Substitute Teacher",
		"Food Critic",
		"Crossing Guard",
		"Notary Public",
		"Insurance Adjuster",
		"Balloon Artist",
	],
}

const templates = [
	() => {
		const t = pick(fragments.times)
		const l = pick(fragments.locations)
		return `${t} at ${l}`
	},
	() => {
		const adj = pick(["Last", "Only", "Greatest", "Remaining"])
		const n = pick(fragments.definiteNouns)
		return `The ${adj} ${n}`
	},
	() => {
		const adv = pick(["Very", "Extremely", "Surprisingly", "Somewhat", "Completely"])
		const adj = pick(fragments.adjectives)
		const n = pick(fragments.eventNouns)
		return `A ${adv} ${adj} ${n}`
	},
	() => {
		const occ = pick(fragments.occupations)
		const l = pick(fragments.locations)
		return `The ${occ} of ${l}`
	},
	() => {
		const adj = pick(fragments.adjectives)
		const n = pick(fragments.eventNouns)
		return `${adj} ${n}`
	},
	() => {
		const occ = pick(fragments.occupations)
		return `My ${occ}`
	},
	() => {
		const n = pick(fragments.eventNouns)
		const l = pick(fragments.locations)
		return `${n} at ${l}`
	},
]

function pick(arr) {
	return arr[Math.floor(Math.random() * arr.length)]
}

export function generateMovieTitle() {
	const template = templates[Math.floor(Math.random() * templates.length)]
	return template()
}
