// Toast copy templates for writing product sales.
// Import buildSaleToast() and pass the product tier, title, studio, and price.
//
// Example output:
//   "Silverline Pictures bought your logline, Midnight at the Mall, for $6."
//   "Your outline for A Very Normal Heist was picked up by Cobalt Gate Films for $220."

// One pool per writing product tier. Each string uses {studio}, {title}, {price}.
// Use several per tier so repeated sales feel varied.
const templates = {
	logline: [
		"{studio} bought your logline, {title}, for {price}.",
		"Sold the logline for {title} to {studio} for {price}.",
		"{studio} optioned your logline, {title}, for {price}.",
		"Your logline, {title}, sold to {studio} for {price}.",
		"{studio} picked up {title} — just a logline, but worth {price}.",
	],
	synopsis: [
		"{studio} bought your synopsis, {title}, for {price}.",
		"Sold the synopsis for {title} to {studio} for {price}.",
		"Your synopsis for {title} went to {studio} for {price}.",
		"{studio} paid {price} for your synopsis, {title}.",
		"A synopsis for {title} — {studio} paid {price} for it.",
	],
	outline: [
		"Your outline for {title} was picked up by {studio} for {price}.",
		"{studio} bought the outline for {title} for {price}.",
		"Sold your outline, {title}, to {studio} for {price}.",
		"{studio} paid {price} for the outline of {title}.",
		"The outline for {title} found a home at {studio} — {price}.",
	],
	treatment: [
		"{studio} bought your treatment, {title}, for {price}.",
		"Your treatment for {title} sold to {studio} for {price}.",
		"Sold the treatment for {title} to {studio} for {price}.",
		"{studio} paid {price} for your treatment of {title}.",
		"{title} — your treatment sold to {studio} for {price}.",
	],
	draftScript: [
		"{studio} bought your draft script, {title}, for {price}.",
		"Sold the draft of {title} to {studio} for {price}.",
		"Your draft script, {title}, went to {studio} for {price}.",
		"{studio} paid {price} for an early draft of {title}.",
		"Draft sold. {studio} picked up {title} for {price}.",
	],
	shootingScript: [
		"Your shooting script, {title}, sold to {studio} for {price}.",
		"{studio} bought a shooting script — {title} — for {price}.",
		"Sold the shooting script for {title} to {studio} for {price}.",
		"{studio} paid {price} for the completed script, {title}.",
	],
}

function pick(arr) {
	return arr[Math.floor(Math.random() * arr.length)]
}

// productTier: one of the keys in `templates` above.
// title: the generated movie title string.
// studio: the buying studio name.
// price: a formatted price string like "$6" or "$1,200".
export function buildSaleToast({ productTier, title, studio, price }) {
	const pool = templates[productTier] ?? templates.logline
	const template = pick(pool)
	return template
		.replace("{studio}", studio)
		.replace("{title}", title)
		.replace("{price}", price)
}
